 func (p replicasOrder) Swap(i, j int) {
 	p[i], p[j] = p[j], p[i]
 }
+
+// getWorkerIndex will return an index holding the replicaSpec for the worker.
+// If the worker doesn't exist, it returns -1.
+func (p replicasOrder) getWorkerIndex() int {
+	for i := range p {
